class Solution:
    def mergeTriplets(self, triplets, target) -> bool:
      seen = set()

      for i in range(3):
        targetVal = target[i]

        # search targetVal from triplets

        for triplet in triplets:

          if triplet[i] == targetVal:
            isValid = True

            # check other values are less than targetVal
            for j in range(3):
              if i == j:
                continue

              if target[j] < triplet[j]:
                isValid = False
                break

            if isValid:
              seen.add(i)
      
      return len(seen) == 3



